krpano.action:
set(hotspot[get(hsname)].alpha, 1.0); 
set(hotspot[get(hsname)].scale, 0.3);
tween(hotspot[get(hsname)].alpha, 0.0, 1.2);
tween(hotspot[get(hsname)].scale, 1.2, 1.2, default, action_pulse(get(hsname)));

txtadd(bname, get(parentname), '_base');
addhotspot(get(bname), hs);
set(hs.type, 'text');

copy(hs.ath, hotspot[get(parentname)].ath);
copy(hs.atv, hotspot[get(parentname)].atv);

set(hs.width, 80); set(hs.height, 80);
set(hs.bgroundedge, 40);
set(hs.bgcolor, 0xFFFFFF); set(hs.bgalpha, 0.6);
set(hs.enabled, false); set(hs.distorted, true);
set(hs.onloaded, action_pulse(get(name)));

txtadd(lname, get(parentname), '_lbl');
addhotspot(get(lname), hs);

set(hs.type, 'text');
set(hs.html, get(labeltext)); 

copy(hs.ath, hotspot[get(parentname)].ath); 
copy(hs.atv, hotspot[get(parentname)].atv);

set(hs.oy, 25); 
set(hs.edge, 'top');
set(hs.distorted, false); set(hs.enabled, false);
set(hs.zorder, 100);

set(hs.bg, true);
set(hs.bgcolor, 0x000000);
set(hs.bgalpha, 0.7);
set(hs.bgroundedge, 5);
set(hs.padding, '5 10');
set(hs.css, 'color:#FFFFFF; font-family:Arial; font-size:14px; font-weight:bold; text-align:center;');
